// Carrega precedentes a ingerir. PRODUÇÃO: substitua o array por um fetch da
// fonte (HTTP -> STF/STJ APIs ou crawler) + parser. Contrato por item:
//   { court, body, case_number(*), rapporteur, judged_at, headnote, thesis,
//     binding, practice_area, verification, source_title, source_url }
// (*) case_number deve ser SEMPRE preenchido com um id estável (nº do processo
//     OU enunciado, ex.: 'Súmula Vinculante 11') — é a chave de idempotência.
const cfg = $('Config').first().json;

const precedents = [
  {
    court: 'STF',
    body: 'Plenário',
    case_number: 'Súmula Vinculante 11',
    rapporteur: '',
    judged_at: '2008-08-22',
    headnote: 'Uso de algemas.',
    thesis: 'Só é lícito o uso de algemas em casos de resistência e de fundado receio de fuga ou de perigo à integridade física própria ou alheia, por parte do preso ou de terceiros, justificada a excepcionalidade por escrito, sob pena de responsabilidade.',
    binding: true,
    practice_area: 'constitucional',
    verification: 'pendente',
    source_title: 'STF — Súmula Vinculante 11',
    source_url: 'https://portal.stf.jus.br/jurisprudencia/sumarioSumulas.asp?base=26'
  }
];

return precedents.map((p) => ({
  json: { ...cfg, ...p, embed_text: [p.headnote, p.thesis].filter(Boolean).join(' | ') }
}));

const src = $('Load Precedents').item.json;
const emb = $json.data[0].embedding;
const vec = '[' + emb.join(',') + ']';

const esc = (s) => String(s).replace(/'/g, "''");
const lit = (s) => (s === null || s === undefined || s === '') ? 'NULL' : `'${esc(s)}'`;
const dat = (s) => (s === null || s === undefined || s === '') ? 'NULL' : `'${esc(s)}'::date`;
const bool = (b) => (b === true || b === 'true') ? 'true' : 'false';

const query = `WITH s AS (
  INSERT INTO legal.source (source_type, title, url, authority, official)
  VALUES ('jurisprudencia', ${lit(src.source_title)}, ${lit(src.source_url)}, ${lit(src.court)}, true)
  ON CONFLICT (source_type, url) WHERE url IS NOT NULL DO UPDATE SET title = EXCLUDED.title
  RETURNING id
),
pr AS (
  INSERT INTO legal.precedent (source_id, court, body, case_number, rapporteur, judged_at, headnote, thesis, binding, practice_area, verification, embedding)
  SELECT s.id, ${lit(src.court)}::legal.court, ${lit(src.body)}, ${lit(src.case_number)}, ${lit(src.rapporteur)}, ${dat(src.judged_at)}, ${lit(src.headnote)}, ${lit(src.thesis)}, ${bool(src.binding)}, ${lit(src.practice_area)}::legal.practice_area, ${lit(src.verification || 'pendente')}::legal.verification_status, '${vec}'::vector
  FROM s
  ON CONFLICT (court, case_number) WHERE case_number IS NOT NULL
  DO UPDATE SET thesis = EXCLUDED.thesis, headnote = EXCLUDED.headnote, embedding = EXCLUDED.embedding
  RETURNING id
)
INSERT INTO legal.document_chunk (source_id, ref_table, ref_id, chunk_index, content, embedding)
SELECT s.id, 'precedent', pr.id, 0, ${lit(src.embed_text)}, '${vec}'::vector
FROM pr CROSS JOIN s
ON CONFLICT (ref_table, ref_id, chunk_index) DO UPDATE SET content = EXCLUDED.content, embedding = EXCLUDED.embedding;`;

return { json: { case_number: src.case_number, query } };
